- (void)setupMessages {
    [self.chatTableView registerClass:[ChatMessageCell class] forCellReuseIdentifier:@"ChatMessageCell"]; // 注册消息单元格类
    self.messages = [MessageModel messagesForAccount:self.aiID];
    if (self.messages.count == 0) {
        [self.messages addObject:[[MessageModel alloc] initWithText:self.options time:[NSDate date] type:MessageTypeReceived accountId:self.aiID cellHeight:[self getStringWidthToCellHeight:self.options] context:@"[]" Done:YES]];
    }
    // 获取最后一个消息，判断接收ai消息时是否被中断，最后一次对话无法完成，所以在这里删除
    MessageModel *lastMessage = [self.messages lastObject];
    if (!lastMessage.done) {
        // 删除最后两个元素
        [self.messages removeLastObject];
        [self.messages removeLastObject];
    }
}

