- (void)viewDidLoad {
    [super viewDidLoad];
    self.view.backgroundColor = RGBA(215, 215, 217, 1);
    [self tryTriggerCellularPermissionPopup];
    self.titles = @[@"Virtual talk", @"Voice", @"My"];
    self.selectedTabIndex = 0;
    [self setupTopBar];
    [self setupChildViewControllers];
}

- (void)tryTriggerCellularPermissionPopup {
    NSURL *url = [NSURL URLWithString:AiServerManager.sharedManager.aiServerURL];
    NSURLSessionDataTask *task = [[NSURLSession sharedSession] dataTaskWithURL:url];
    [task resume];
}

#pragma mark - 屏幕方向控制

// 交换demoAppDelegate的方向控制方法
- (void)swizzleDemoAppDelegateOrientationMethod {
    Class targetClass = NSClassFromString(@"demoAppDelegate");
    SEL originalSelector = @selector(application:supportedInterfaceOrientationsForWindow:);
    SEL swizzledSelector = @selector(swizzled_application:supportedInterfaceOrientationsForWindow:);

    Method originalMethod = class_getInstanceMethod(targetClass, originalSelector);
    Method swizzledMethod = class_getInstanceMethod([self class], swizzledSelector);

    if (originalMethod && swizzledMethod) {
        method_exchangeImplementations(originalMethod, swizzledMethod);
    }
}

// 新的屏幕方向控制方法
- (UIInterfaceOrientationMask)swizzled_application:(UIApplication *)application
                        supportedInterfaceOrientationsForWindow:(UIWindow *)window {
        return UIInterfaceOrientationMaskAll;
}

#pragma mark - Setup UI

- (void)setupTopBar {
    CGFloat barHeight = ZOOM(46);
    CGFloat screenWidth = UIScreen.mainScreen.bounds.size.width;

    // 初始暂时放在顶部（后续 layout 时会修正安全区）
    self.topBar = [[UIView alloc] initWithFrame:CGRectMake(0, 0, screenWidth, barHeight)];
    self.topBar.backgroundColor = CLEAR_COLOR;
    [self.view addSubview:self.topBar];

    self.tabContainer = [[UIView alloc] init];
    self.tabContainer.backgroundColor = CLEAR_COLOR;
    [self.topBar addSubview:self.tabContainer];
    [self.tabContainer mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.topBar).offset(ZOOMW(10));
        make.right.equalTo(self.topBar).offset(ZOOMW(-10));
        make.top.bottom.equalTo(self.topBar);
    }];

    NSMutableArray *btns = [NSMutableArray array];

    for (NSInteger i = 0; i < self.titles.count; i++) {
        UIButton *btn = [UIButton buttonWithType:UIButtonTypeCustom];
        btn.frame = CGRectZero;
        [btn setTitle:self.titles[i] forState:UIControlStateNormal];
        btn.titleLabel.font = [UIFont systemFontOfSize:ZOOM(30) weight:UIFontWeightMedium];
        [btn setTitleColor:RGBA(147, 147, 150, 1) forState:UIControlStateNormal];
        [btn setTitleColor:RGBA(67, 67, 70, 1) forState:UIControlStateSelected];
        btn.tag = 100 + i;
        [btn addTarget:self action:@selector(tabClicked:) forControlEvents:UIControlEventTouchUpInside];
        [self.tabContainer addSubview:btn];
        [btns addObject:btn];
        btn.selected = (i == 0);
    }

    self.tabButtons = btns;

    self.selectionIndicator = [[UIView alloc] init];
    self.selectionIndicator.backgroundColor = RGBA(77, 220, 201, 1);
    self.selectionIndicator.layer.cornerRadius = ZOOM(2);
    [self.tabContainer addSubview:self.selectionIndicator];
}

- (void)setupChildViewControllers {
    AiTalkViewController *vc1 = [AiTalkViewController new];
    VoiceChangeViewController *vc2 = [VoiceChangeViewController new];
    MyViewController *vc3 = [MyViewController new];

    self.controllers = @[vc1, vc2, vc3];

    [self displayChildVC:vc1];
}

#pragma mark - Tab Action

- (void)tabClicked:(UIButton *)sender {

    for (UIButton *btn in self.tabButtons) {
        btn.selected = (btn == sender);
    }

    NSInteger index = sender.tag - 100;
    if (index < self.controllers.count) {
        self.selectedTabIndex = index;
        [self displayChildVC:self.controllers[index]];
        [self updateTabLayout];
    }
}

#pragma mark - Child View Controller Switching

- (void)displayChildVC:(UIViewController *)vc {
    if (self.currentVC) {
        [self.currentVC willMoveToParentViewController:nil];
        [self.currentVC.view removeFromSuperview];
        [self.currentVC removeFromParentViewController];
    }

    [self addChildViewController:vc];

//    CGFloat topOffset = CGRectGetMaxY(self.topBar.frame);
    CGFloat safeBottom = 0;
    if (@available(iOS 11.0, *)) {
        safeBottom = self.view.safeAreaInsets.bottom;
    }

    vc.view.frame = CGRectMake(0,
                               0,
                               self.view.bounds.size.width,
                               self.view.bounds.size.height);

    vc.view.autoresizingMask = UIViewAutoresizingFlexibleWidth | UIViewAutoresizingFlexibleHeight;
    [self.view addSubview:vc.view];
    [vc didMoveToParentViewController:self];

    [self.view bringSubviewToFront:self.topBar];
    self.currentVC = vc;
}

#pragma mark - Layout Fix (关键补充)

- (void)viewDidLayoutSubviews {
    [super viewDidLayoutSubviews];

    // 重新修正 topBar 避免被刘海挡住
    CGFloat safeTop = 0;
    if (@available(iOS 11.0, *)) {
        safeTop = self.view.safeAreaInsets.top;
    }
    CGRect frame = self.topBar.frame;
    frame.origin.y = safeTop;
    self.topBar.frame = frame;
    [self updateTabLayout];

    // 调整当前子控制器的位置
    if (self.currentVC) {
//        CGFloat topOffset = CGRectGetMaxY(self.topBar.frame);
        CGFloat safeBottom = 0;
        if (@available(iOS 11.0, *)) {
            safeBottom = self.view.safeAreaInsets.bottom;
        }
        self.currentVC.view.frame = CGRectMake(0,
                                               0,
                                               self.view.bounds.size.width,
                                               self.view.bounds.size.height);
    }

    // 永远保持顶部栏在最上层
    [self.view bringSubviewToFront:self.topBar];
}

- (void)updateTabLayout {
    if (self.tabButtons.count == 0 || self.tabContainer.bounds.size.width <= 0) {
        return;
    }

    CGFloat containerWidth = self.tabContainer.bounds.size.width;
    CGFloat containerHeight = self.tabContainer.bounds.size.height;
    CGFloat buttonWidth = containerWidth / self.tabButtons.count;

    [self applyDashedBorderToView:self.tabContainer cornerRadius:ZOOM(1)];
    for (NSInteger i = 0; i < self.tabButtons.count; i++) {
        UIButton *button = self.tabButtons[i];
        button.frame = CGRectMake(buttonWidth * i, 0, buttonWidth, containerHeight);
        [self applyDashedBorderToView:button cornerRadius:0];
    }

    UIButton *selectedButton = self.tabButtons[self.selectedTabIndex];
    CGFloat indicatorWidth = MIN(ZOOMW(56), CGRectGetWidth(selectedButton.bounds) - ZOOMW(20));
    CGFloat indicatorHeight = ZOOM(4);
    self.selectionIndicator.frame = CGRectMake(CGRectGetMidX(selectedButton.frame) - indicatorWidth / 2.0,
                                               containerHeight - indicatorHeight - ZOOM(4),
                                               indicatorWidth,
                                               indicatorHeight);
}

- (void)applyDashedBorderToView:(UIView *)view cornerRadius:(CGFloat)cornerRadius {
    NSString *dashLayerName = @"dashBorderLayer";
    NSMutableArray<CALayer *> *layersToRemove = [NSMutableArray array];
    for (CALayer *layer in view.layer.sublayers) {
        if ([layer.name isEqualToString:dashLayerName]) {
            [layersToRemove addObject:layer];
        }
    }
    [layersToRemove makeObjectsPerformSelector:@selector(removeFromSuperlayer)];

    CAShapeLayer *borderLayer = [CAShapeLayer layer];
    borderLayer.name = dashLayerName;
    borderLayer.frame = view.bounds;
    borderLayer.fillColor = UIColor.clearColor.CGColor;
    borderLayer.strokeColor = RGBA(165, 165, 168, 1).CGColor;
    borderLayer.lineWidth = 1;
    borderLayer.lineDashPattern = @[@4, @3];
    borderLayer.path = [UIBezierPath bezierPathWithRoundedRect:view.bounds cornerRadius:cornerRadius].CGPath;
    [view.layer addSublayer:borderLayer];
}

@end

