    for (CALayer *layer in targetView.layer.sublayers) {
        if ([layer.name isEqualToString:dashLayerName]) {
            [layersToRemove addObject:layer];
        }
    }
    [layersToRemove makeObjectsPerformSelector:@selector(removeFromSuperlayer)];

    CAShapeLayer *shape = [CAShapeLayer layer];
    shape.name = dashLayerName;
    shape.frame = targetView.bounds;
    shape.fillColor = UIColor.clearColor.CGColor;
    shape.strokeColor = RGBA(164, 164, 166, 1).CGColor;
    shape.lineWidth = 1;
    shape.lineDashPattern = @[@3, @2];
    shape.path = [UIBezierPath bezierPathWithRect:targetView.bounds].CGPath;
    [targetView.layer addSublayer:shape];
