- (void)configureWithMessage:(MessageModel *)message iconSendImage:(UIImage*)sicon iconReceiveImage:(UIImage*)ricon topicName:(NSString*)name options:(NSString*)options {
    // 先清除旧的 textView 防止重用时出现重复
    [[self.contentView viewWithTag:999] removeFromSuperview];

    if (message.type == MessageTypeSent) {
        // 设置发送消息的样式
        self.type=MessageTypeSent;
        self.bubbleView.backgroundColor = RGBA(104, 205, 167, 1);
        self.messageLabel.textColor = WHITE_COLOR;
        self.avatarImageView.image = sicon;

        // 配置发送消息的头像和气泡约束
        [_avatarImageView mas_remakeConstraints:^(MASConstraintMaker *make) {
            make.top.equalTo(self.contentView).offset(ZOOM(10));
            make.width.height.mas_equalTo(ZOOM(40));
            make.right.equalTo(self.contentView).offset(ZOOMW(-16));
        }];
        [_bubbleView mas_remakeConstraints:^(MASConstraintMaker *make) {
            make.top.equalTo(self.contentView).offset(ZOOM(10));
            make.bottom.equalTo(self.contentView).offset(ZOOM(-10));
            make.width.lessThanOrEqualTo(@(ZOOMW(280)));
            make.right.equalTo(self.contentView).offset(ZOOMW(-12));
        }];
        self.messageLabel.hidden = NO;
    } else {
        // 设置接收消息的样式
        self.type=MessageTypeReceived;
        self.bubbleView.backgroundColor = RGBA(245, 245, 247, 1);
        self.messageLabel.textColor = RGBA(84, 84, 87, 1);
        self.avatarImageView.image = ricon;
        // 配置接收消息的头像和气泡约束
        [self.avatarImageView mas_remakeConstraints:^(MASConstraintMaker *make) {
            make.top.equalTo(self.contentView).offset(ZOOM(10));
            make.width.height.mas_equalTo(ZOOM(40));
            make.left.equalTo(self.contentView).offset(ZOOMW(8));
        }];
        [self.bubbleView mas_remakeConstraints:^(MASConstraintMaker *make) {
            make.top.equalTo(self.contentView).offset(ZOOM(10));
            make.bottom.equalTo(self.contentView).offset(ZOOM(-10));
            make.width.lessThanOrEqualTo(@(ZOOMW(280)));
            make.left.equalTo(self.avatarImageView.mas_right).offset(ZOOMW(8));
        }];

        // 检查是否需要富文本内容
        if ([message.text isEqualToString:options]) {
            UITextView *textView = [[UITextView alloc] init];
            textView.editable = NO;
            textView.scrollEnabled = NO;
            textView.backgroundColor = [UIColor clearColor];
            textView.delegate = self;
            textView.tag = 999; // 设置一个标识符，方便查找和移除

            NSMutableAttributedString *attributedText = [[NSMutableAttributedString alloc] initWithString:message.text];
            NSArray *lines = [message.text componentsSeparatedByString:@"\n"];
            NSInteger offset = 0;

            for (NSString *line in lines) {
                UIFont *font = [UIFont systemFontOfSize:16.0];
                NSString *searchPrefix = [NSString stringWithFormat:@"@%@：", name];
                NSRange prefixRange = [line rangeOfString:searchPrefix];

                if (prefixRange.location != NSNotFound) {
                    // 设置前缀为绿色
                    NSRange absolutePrefixRange = NSMakeRange(offset + prefixRange.location, prefixRange.length);
                    [attributedText addAttribute:NSForegroundColorAttributeName value:DEEP_COLOR range:absolutePrefixRange];
                    [attributedText addAttribute:NSFontAttributeName value:font range:absolutePrefixRange];

                    // 创建超链接
                    NSString *linkURLString = [NSString stringWithFormat:@"customLink://%@", line];
                    NSString *encodedLinkURLString = [linkURLString stringByAddingPercentEncodingWithAllowedCharacters:[NSCharacterSet URLFragmentAllowedCharacterSet]];
                    NSURL *linkURL = [NSURL URLWithString:encodedLinkURLString];

                    if (linkURL) {
                        [attributedText addAttribute:NSLinkAttributeName value:linkURL range:absolutePrefixRange];
                    }

                    // 设置内容的颜色和字体
                    NSRange contentRange = NSMakeRange(NSMaxRange(absolutePrefixRange), line.length - prefixRange.length);
                    [attributedText addAttribute:NSForegroundColorAttributeName value:[UIColor blackColor] range:contentRange];
                    [attributedText addAttribute:NSFontAttributeName value:font range:contentRange];
                }
                offset += line.length + 1;
            }

            textView.attributedText = attributedText;
            self.messageLabel.hidden = YES;
            [self.bubbleView addSubview:textView];

            // 设置 textView 的约束
            [textView mas_makeConstraints:^(MASConstraintMaker *make) {
                make.top.equalTo(self.bubbleView).offset(ZOOM(2));
                make.left.equalTo(self.bubbleView).offset(ZOOMW(5));
                make.right.equalTo(self.bubbleView).offset(-ZOOMW(5));
            }];
        } else {
            self.messageLabel.hidden = NO;
        }
    }

