   256	- (void)applyDashedBorderToView:(UIView *)view cornerRadius:(CGFloat)cornerRadius {
   257	    NSString *dashLayerName = @"dashBorderLayer";
   258	    NSMutableArray<CALayer *> *layersToRemove = [NSMutableArray array];
   259	    for (CALayer *layer in view.layer.sublayers) {
   260	        if ([layer.name isEqualToString:dashLayerName]) {
   261	            [layersToRemove addObject:layer];
   262	        }
   263	    }
   264	    [layersToRemove makeObjectsPerformSelector:@selector(removeFromSuperlayer)];
   265	
   266	    CAShapeLayer *borderLayer = [CAShapeLayer layer];
   267	    borderLayer.name = dashLayerName;
   268	    borderLayer.frame = view.bounds;
   269	    borderLayer.fillColor = UIColor.clearColor.CGColor;
   270	    borderLayer.strokeColor = RGBA(165, 165, 168, 1).CGColor;
   271	    borderLayer.lineWidth = 1;
   272	    borderLayer.lineDashPattern = @[@4, @3];
   273	    borderLayer.path = [UIBezierPath bezierPathWithRoundedRect:view.bounds cornerRadius:cornerRadius].CGPath;
   274	    [view.layer addSublayer:borderLayer];
   275	}
