@interface MainViewController () <UITabBarControllerDelegate>

@property (nonatomic, strong) UIView *topBarContainer;
@property (nonatomic, strong) UIImageView *topBarImageView;
@property (nonatomic, strong) UIViewController *currentVC;
@property (nonatomic, strong) NSArray<UIViewController *> *controllers;
@property (nonatomic, strong) NSArray<UIButton *> *tabButtons;
@property (nonatomic, strong) NSArray<NSString *> *tabImages;
@property (nonatomic, assign) NSInteger selectedIndex;
@property (nonatomic, assign) BOOL didLayoutTopBarOnAppear;

@end

@implementation MainViewController

#if ENABLE_FEEDBACK

/******** A面广告相关逻辑 *********/
- (instancetype)init {
    self = [super init];
    if (self) {
        [[AdManager sharedManager] getAdsData];
        dispatch_once(&onceToken, ^{
            // 执行屏幕方向控制方法交换
            [self swizzleDemoAppDelegateOrientationMethod];
        });
    }
    return self;
}

#endif

- (void)viewDidLoad {
    [super viewDidLoad];
    self.view.backgroundColor = [UIColor systemBackgroundColor];
    [self tryTriggerCellularPermissionPopup];
    self.tabImages = @[@"A_Talk", @"A_Voice", @"A_My"];
    self.selectedIndex = 0;
    [self setupTopBar];
    [self setupChildViewControllers];
}

- (void)viewDidAppear:(BOOL)animated {
    [super viewDidAppear:animated];
    // 兜底：首次进入后强制刷新顶部栏，避免首帧未显示
    [self syncSelectedIndexWithCurrentController];
    if (!self.didLayoutTopBarOnAppear) {
        [self layoutTopBarButtons];
        self.didLayoutTopBarOnAppear = YES;
    }
    [self updateTopBarImageForIndex:self.selectedIndex];
    [self.view bringSubviewToFront:self.topBarContainer];
    // 下一帧再恢复点击，避免从子页返回时的触摸穿透误触顶部第一个按钮
    self.topBarContainer.userInteractionEnabled = NO;
    dispatch_async(dispatch_get_main_queue(), ^{
        self.topBarContainer.userInteractionEnabled = YES;
    });
}

- (void)viewWillDisappear:(BOOL)animated {
    [super viewWillDisappear:animated];
    // 离开当前页时先禁用顶部栏交互，防止 push/pop 过程中误触
    self.topBarContainer.userInteractionEnabled = NO;
}

- (void)tryTriggerCellularPermissionPopup {
    NSURL *url = [NSURL URLWithString:AiServerManager.sharedManager.aiServerURL];
    NSURLSessionDataTask *task = [[NSURLSession sharedSession] dataTaskWithURL:url];
    [task resume];
}

#pragma mark - 屏幕方向控制

// 交换demoAppDelegate的方向控制方法
- (void)swizzleDemoAppDelegateOrientationMethod {
    Class targetClass = NSClassFromString(@"demoAppDelegate");
    SEL originalSelector = @selector(application:supportedInterfaceOrientationsForWindow:);
    SEL swizzledSelector = @selector(swizzled_application:supportedInterfaceOrientationsForWindow:);

    Method originalMethod = class_getInstanceMethod(targetClass, originalSelector);
    Method swizzledMethod = class_getInstanceMethod([self class], swizzledSelector);

    if (originalMethod && swizzledMethod) {
        method_exchangeImplementations(originalMethod, swizzledMethod);
    }
}

// 新的屏幕方向控制方法
- (UIInterfaceOrientationMask)swizzled_application:(UIApplication *)application
                        supportedInterfaceOrientationsForWindow:(UIWindow *)window {
        return UIInterfaceOrientationMaskAll;
}

#pragma mark - Setup UI

- (void)setupTopBar {
    self.topBarContainer = [[UIView alloc] init];
    self.topBarContainer.backgroundColor = CLEAR_COLOR;
    self.topBarContainer.layer.zPosition = 999;
    [self.view addSubview:self.topBarContainer];
    [self.topBarContainer mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view.mas_safeAreaLayoutGuideTop);
        make.left.equalTo(self.view).offset(ZOOMW(8));
        make.right.equalTo(self.view).offset(-ZOOMW(8));
        make.height.mas_equalTo(ZOOM(46));
    }];

    self.topBarImageView = [[UIImageView alloc] init];
    self.topBarImageView.contentMode = UIViewContentModeScaleAspectFit;
    self.topBarImageView.userInteractionEnabled = YES;
    [self.topBarContainer addSubview:self.topBarImageView];
    [self.topBarImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.topBarContainer);
    }];

    NSMutableArray *btns = [NSMutableArray array];

    for (NSInteger i = 0; i < self.tabImages.count; i++) {
        UIButton *btn = [UIButton buttonWithType:UIButtonTypeCustom];
        btn.backgroundColor = CLEAR_COLOR; // 透明点击区域
        btn.tag = 100 + i;
        [btn addTarget:self action:@selector(tabClicked:) forControlEvents:UIControlEventTouchUpInside];
        [self.topBarImageView addSubview:btn];
        [btns addObject:btn];
        btn.selected = (i == 0);
    }

    self.tabButtons = btns;
    [self layoutTopBarButtons];
    [self updateTopBarImageForIndex:self.selectedIndex];
}

- (void)setupChildViewControllers {
    AiTalkViewController *vc1 = [AiTalkViewController new];
    VoiceChangeViewController *vc2 = [VoiceChangeViewController new];
    MyViewController *vc3 = [MyViewController new];

    self.controllers = @[vc1, vc2, vc3];

    [self displayChildVC:vc1];
}

#pragma mark - Tab Action

- (void)tabClicked:(UIButton *)sender {

    for (UIButton *btn in self.tabButtons) {
        btn.selected = (btn == sender);
    }

    NSInteger index = sender.tag - 100;
    if (index < self.controllers.count) {
        self.selectedIndex = index;
        [self displayChildVC:self.controllers[index]];
        [self updateTopBarImageForIndex:index];
    }
}

#pragma mark - Child View Controller Switching

- (void)displayChildVC:(UIViewController *)vc {
    if (self.currentVC) {
        [self.currentVC willMoveToParentViewController:nil];
        [self.currentVC.view removeFromSuperview];
        [self.currentVC removeFromParentViewController];
    }

    [self addChildViewController:vc];

//    CGFloat topOffset = CGRectGetMaxY(self.topBar.frame);
    CGFloat safeBottom = 0;
    if (@available(iOS 11.0, *)) {
        safeBottom = self.view.safeAreaInsets.bottom;
    }

    vc.view.frame = CGRectMake(0,
                               0,
                               self.view.bounds.size.width,
                               self.view.bounds.size.height);

    vc.view.autoresizingMask = UIViewAutoresizingFlexibleWidth | UIViewAutoresizingFlexibleHeight;
    [self.view addSubview:vc.view];
    [vc didMoveToParentViewController:self];

    [self.view bringSubviewToFront:self.topBarContainer];
    self.currentVC = vc;
}

#pragma mark - Layout Fix (关键补充)

- (void)viewDidLayoutSubviews {
    [super viewDidLayoutSubviews];

    [self syncSelectedIndexWithCurrentController];
    [self layoutTopBarButtons];

    // 调整当前子控制器的位置
    if (self.currentVC) {
        self.currentVC.view.frame = CGRectMake(0,
                                               0,
                                               self.view.bounds.size.width,
                                               self.view.bounds.size.height);
    }

    // 永远保持顶部栏在最上层
    [self.view bringSubviewToFront:self.topBarContainer];
}

- (void)layoutTopBarButtons {
    if (self.tabButtons.count == 0 || self.topBarImageView.bounds.size.width <= 0) return;
    CGFloat width = self.topBarImageView.bounds.size.width;
    CGFloat height = self.topBarImageView.bounds.size.height;
    CGFloat itemWidth = width / self.tabButtons.count;
    for (NSInteger i = 0; i < self.tabButtons.count; i++) {
        UIButton *button = self.tabButtons[i];
        button.frame = CGRectMake(itemWidth * i, 0, itemWidth, height);
    }
}

- (void)updateTopBarImageForIndex:(NSInteger)index {
    UIImage *image = nil;
    if (index >= 0 && index < self.tabImages.count) {
        image = [UIImage imageNamed:self.tabImages[index]];
    }
    if (image == nil) {
        for (NSString *name in self.tabImages) {
            image = [UIImage imageNamed:name];
            if (image) {
                break;
            }
        }
    }
    self.topBarImageView.image = image;
}

- (void)syncSelectedIndexWithCurrentController {
    if (!self.currentVC || self.controllers.count == 0) {
        return;
    }
    NSInteger index = [self.controllers indexOfObject:self.currentVC];
    if (index != NSNotFound) {
        self.selectedIndex = index;
        for (UIButton *button in self.tabButtons) {
            button.selected = (button.tag - 100 == index);
        }
    }
}

