        [textField resignFirstResponder];
    }
    return YES;
}

- (void)keyboardWillShow:(NSNotification *)notification {
    // 获取键盘的高度
    CGRect keyboardEndFrame = [[[notification userInfo] objectForKey:UIKeyboardFrameEndUserInfoKey] CGRectValue];
    NSTimeInterval duration = [notification.userInfo[UIKeyboardAnimationDurationUserInfoKey] doubleValue];
    UIViewAnimationOptions options = ([notification.userInfo[UIKeyboardAnimationCurveUserInfoKey] integerValue] << 16);

    CGFloat keyboardHeight = CGRectGetHeight(keyboardEndFrame);
    CGFloat safeBottom = 0;
    if (@available(iOS 11.0, *)) {
        safeBottom = self.view.safeAreaInsets.bottom;
    }
    [self.messageViewBottomConstraint setOffset:-(keyboardHeight - safeBottom)];
    [UIView animateWithDuration:duration delay:0 options:options animations:^{
        [self.view layoutIfNeeded];
    } completion:nil];
}

- (void)keyboardWillHide:(NSNotification *)notification {
    NSTimeInterval duration = [notification.userInfo[UIKeyboardAnimationDurationUserInfoKey] doubleValue];
    UIViewAnimationOptions options = ([notification.userInfo[UIKeyboardAnimationCurveUserInfoKey] integerValue] << 16);
    [self.messageViewBottomConstraint setOffset:0];
    [UIView animateWithDuration:duration delay:0 options:options animations:^{
        [self.view layoutIfNeeded];
    } completion:nil];
}

#pragma mark - 计算消息文本内容的高度和换行情况

- (NSInteger)getStringWidthToCellHeight:(NSString *)string {
    // 将文本分割为行
    NSArray *lines = [string componentsSeparatedByString:@"\n"];

    // 计算空行数
    NSPredicate *isEmptyLinePredicate = [NSPredicate predicateWithBlock:^BOOL(id _Nullable evaluatedObject, NSDictionary * _Nullable bindings) {
        return ([evaluatedObject isKindOfClass:[NSString class]] && [(NSString *)evaluatedObject length] == 0);
    }];
    NSArray *emptyLines = [lines filteredArrayUsingPredicate:isEmptyLinePredicate];
